package org.openmetadata.service.apps.scheduler;

import lombok.extern.slf4j.Slf4j;
import org.openmetadata.service.jdbi3.CollectionDAO;
import org.openmetadata.service.search.SearchRepository;
import org.quartz.Job;
import org.quartz.JobDetail;
import org.quartz.Scheduler;
import org.quartz.SchedulerException;
import org.quartz.simpl.SimpleJobFactory;
import org.quartz.spi.TriggerFiredBundle;

@Slf4j
public class CustomJobFactory extends SimpleJobFactory {
  private final CollectionDAO collectionDAO;
  private final SearchRepository searchRepository;

  public CustomJobFactory(CollectionDAO collectionDAO, SearchRepository searchRepository) {
    super();
    this.collectionDAO = collectionDAO;
    this.searchRepository = searchRepository;
  }

  @Override
  public Job newJob(TriggerFiredBundle bundle, Scheduler Scheduler) throws SchedulerException {
    JobDetail jobDetail = bundle.getJobDetail();
    Class<? extends Job> jobClass = jobDetail.getJobClass();

    try {
      LOG.debug("Producing instance of Job '{}', class={}", jobDetail.getKey(), jobClass.getName());

      return jobClass
          .getDeclaredConstructor(CollectionDAO.class, SearchRepository.class)
          .newInstance(collectionDAO, searchRepository);
    } catch (Exception var7) {
      throw new SchedulerException(
          "Problem instantiating class '" + jobDetail.getJobClass().getName() + "'", var7);
    }
  }
}

package org.openmetadata.service.config;

import com.fasterxml.jackson.annotation.JsonProperty;
import java.util.Collections;
import java.util.Map;
import org.openmetadata.service.config.web.HeaderFactory;

public class ReferrerPolicyHeaderFactory extends HeaderFactory {
  public static final String REFERRER_POLICY_HEADER = "Referrer-Policy";
  @JsonProperty private ReferrerPolicyOption option;

  public ReferrerPolicyHeaderFactory() {
    this.option = ReferrerPolicyOption.NO_REFERRER;
  }

  public ReferrerPolicyOption getOption() {
    return this.option;
  }

  public void setOption(ReferrerPolicyOption option) {
    this.option = option;
  }

  @Override
  public Map<String, String> buildHeaders() {
    return Collections.singletonMap(REFERRER_POLICY_HEADER, this.option.getValue());
  }

  public enum ReferrerPolicyOption {
    NO_REFERRER("no-referrer"),
    NO_REFERRER_WHEN_DOWNGRADE("no-referrer-when-downgrade"),
    ORIGIN("origin"),
    ORIGIN_WHEN_CROSS_ORIGIN("origin-when-cross-origin"),
    SAME_ORIGIN("same-origin"),
    STRICT_ORIGIN("strict-origin"),
    STRICT_ORIGIN_WHEN_CROSS_ORIGIN("strict-origin-when-cross-origin"),
    UNSAFE_URL("unsafe-url");

    private final String value;

    ReferrerPolicyOption(String value) {
      this.value = value;
    }

    public String getValue() {
      return this.value;
    }
  }
}

package org.openmetadata.service.config;

import com.fasterxml.jackson.annotation.JsonProperty;
import jakarta.validation.constraints.AssertTrue;
import jakarta.validation.constraints.NotBlank;
import lombok.Getter;
import lombok.Setter;
import org.apache.commons.lang3.StringUtils;

@Getter
@Setter
public class S3Configuration {

  @JsonProperty("bucketName")
  @NotBlank(message = "Bucket name must be provided")
  private String bucketName;

  @JsonProperty("region")
  @NotBlank(message = "Region must be provided")
  private String region;

  @JsonProperty("accessKey")
  private String accessKey;

  @JsonProperty("secretKey")
  private String secretKey;

  @JsonProperty("useIamRole")
  private boolean useIamRole = false;

  @JsonProperty("iamRoleArn")
  private String iamRoleArn;

  @JsonProperty("endpoint")
  private String endpoint;

  @JsonProperty("cloudFrontUrl")
  private String cloudFrontUrl;

  @JsonProperty("cloudFrontKeyId")
  private String cloudFrontKeyPairId;

  @JsonProperty("cloudFrontPrivateKeyPath")
  private String cloudFrontPrivateKeyPath;

  @JsonProperty("prefixPath")
  private String prefixPath;

  @JsonProperty("sseAlgorithm")
  private String sseAlgorithm;

  @JsonProperty("kmsKeyId")
  private String kmsKeyId;

  @AssertTrue(
      message = "Either useIamRole must be true or both accessKey and secretKey must be provided")
  public boolean isValidCredentials() {
    if (useIamRole) {
      return true;
    } else {
      return StringUtils.isNotBlank(accessKey) && StringUtils.isNotBlank(secretKey);
    }
  }
}

package org.openmetadata.service.governance.workflows.elements;

import java.util.ArrayList;
import java.util.List;
import org.flowable.bpmn.model.BpmnModel;
import org.flowable.bpmn.model.FlowableListener;
import org.flowable.bpmn.model.Process;
import org.openmetadata.service.governance.workflows.WorkflowInstanceListener;
import org.openmetadata.service.governance.workflows.flowable.builders.FlowableListenerBuilder;

public interface TriggerInterface {
  String getTriggerWorkflowId();

  void addToWorkflow(BpmnModel model);

  default void attachWorkflowInstanceListeners(Process process) {
    for (FlowableListener listener : getWorkflowInstanceListeners()) {
      process.getExecutionListeners().add(listener);
    }
  }

  default List<FlowableListener> getWorkflowInstanceListeners(List<String> events) {
    List<FlowableListener> listeners = new ArrayList<>();

    for (String event : events) {
      FlowableListener listener =
          new FlowableListenerBuilder()
              .event(event)
              .implementation(WorkflowInstanceListener.class.getName())
              .build();
      listeners.add(listener);
    }

    return listeners;
  }

  private List<FlowableListener> getWorkflowInstanceListeners() {
    return getWorkflowInstanceListeners(List.of("start", "end"));
  }
}

package org.openmetadata.service.governance.workflows.flowable.builders;

import java.util.ArrayList;
import java.util.List;
import org.flowable.bpmn.model.FieldExtension;
import org.flowable.bpmn.model.FlowableListener;

public class FlowableListenerBuilder {
  private String event;
  private String implementation;
  private String implementationType = "class";
  private final List<FieldExtension> fieldExtensions = new ArrayList<>();

  public FlowableListenerBuilder event(String event) {
    this.event = event;
    return this;
  }

  public FlowableListenerBuilder implementation(String implementation) {
    this.implementation = implementation;
    return this;
  }

  public FlowableListenerBuilder implementationType(String implementationType) {
    this.implementationType = implementationType;
    return this;
  }

  public FlowableListenerBuilder addFieldExtension(FieldExtension fieldExtension) {
    this.fieldExtensions.add(fieldExtension);
    return this;
  }

  public FlowableListener build() {
    FlowableListener listener = new FlowableListener();
    listener.setEvent(event);
    listener.setImplementationType(implementationType);
    listener.setImplementation(implementation);

    for (FieldExtension fieldExtension : fieldExtensions) {
      listener.getFieldExtensions().add(fieldExtension);
    }
    return listener;
  }
}

package org.openmetadata.service.jdbi3;

import java.util.List;
import java.util.UUID;
import lombok.extern.slf4j.Slf4j;
import org.openmetadata.schema.TokenInterface;
import org.openmetadata.schema.utils.JsonUtils;
import org.openmetadata.service.Entity;
import org.openmetadata.service.exception.EntityNotFoundException;

@Slf4j
@Repository
public class TokenRepository {
  static final String TOKEN_NOT_PRESENT_MSG = "Token not present for the user";
  private final CollectionDAO dao;

  public TokenRepository() {
    this.dao = Entity.getCollectionDAO();
  }

  public TokenInterface findByToken(String token) {
    TokenInterface result = dao.getTokenDAO().findByToken(token);
    if (result == null) {
      throw new EntityNotFoundException("Invalid Request Token. Please check your Token");
    }
    return result;
  }

  public List<TokenInterface> findByUserIdAndType(UUID userId, String type) {
    return dao.getTokenDAO().getAllUserTokenWithType(userId, type);
  }

  public void insertToken(TokenInterface tokenInterface) {
    dao.getTokenDAO().insert(JsonUtils.pojoToJson(tokenInterface));
  }

  public void deleteToken(String token) {
    try {
      dao.getTokenDAO().delete(token);
    } catch (Exception ex) {
      LOG.info(TOKEN_NOT_PRESENT_MSG);
    }
  }

  public void deleteAllToken(List<String> tokens) {
    try {
      dao.getTokenDAO().deleteAll(tokens);
    } catch (Exception ex) {
      LOG.info(TOKEN_NOT_PRESENT_MSG);
    }
  }

  public void deleteTokenByUserAndType(UUID userId, String type) {
    try {
      dao.getTokenDAO().deleteTokenByUserAndType(userId, type);
    } catch (Exception ex) {
      LOG.info(TOKEN_NOT_PRESENT_MSG);
    }
  }
}

