package org.openmetadata.service.migration.context;

import java.util.HashMap;
import java.util.List;
import lombok.Getter;
import lombok.extern.slf4j.Slf4j;
import org.jdbi.v3.core.Handle;
import org.openmetadata.service.migration.api.MigrationProcess;

@Slf4j
public class MigrationWorkflowContext {
  @Getter private final HashMap<String, MigrationContext> migrationContext;
  private final Handle handle;

  public MigrationWorkflowContext(Handle handle) {
    this.migrationContext = new HashMap<>();
    this.handle = handle;
  }

  public void computeInitialContext(String currentMaxMigrationVersion) {
    computeMigrationSafely(new MigrationContext(currentMaxMigrationVersion, List.of(), handle));
  }

  public void computeMigrationContext(MigrationProcess process, boolean compute) {
    MigrationContext context =
        new MigrationContext(process.getVersion(), process.getMigrationOps(), handle);
    if (compute) {
      computeMigrationSafely(context);
    } else {
      this.migrationContext.put(context.getVersion(), context);
    }
  }

  private void computeMigrationSafely(MigrationContext context) {
    try {
      context.compute();
      context.show();
      this.migrationContext.put(context.getVersion(), context);
    } catch (Exception e) {
      LOG.warn("Error computing context for [{}] due to [{}]", context.getVersion(), e);
    }
  }
}

package org.openmetadata.service.migration.mysql.v1110;

import java.util.Map;
import lombok.SneakyThrows;
import lombok.extern.slf4j.Slf4j;
import org.openmetadata.service.jdbi3.locator.ConnectionType;
import org.openmetadata.service.migration.QueryStatus;
import org.openmetadata.service.migration.api.MigrationProcessImpl;
import org.openmetadata.service.migration.utils.MigrationFile;
import org.openmetadata.service.migration.utils.v1110.MigrationUtil;

@Slf4j
public class Migration extends MigrationProcessImpl {
  private final MigrationUtil migrationUtil;

  public Migration(MigrationFile migrationFile) {
    super(migrationFile);
    this.migrationUtil = new MigrationUtil(ConnectionType.MYSQL, migrationFile);
  }

  @Override
  public Map<String, QueryStatus> runPostDDLScripts(boolean isForceMigration) {
    Map<String, QueryStatus> result = super.runPostDDLScripts(isForceMigration);
    result.putAll(
        migrationUtil.setRecognizersForSensitiveTags(
            "UPDATE tag SET json = JSON_SET(json, '$.recognizers', CAST(? AS JSON)) "
                + "WHERE JSON_EXTRACT(json, '$.fullyQualifiedName') = ?",
            handle,
            migrationDAO,
            isForceMigration));
    return result;
  }

  @Override
  @SneakyThrows
  public void runDataMigration() {
    // Flyway history migration is now handled in MigrationWorkflow.loadMigrations()
    // before parsing SQL files, to ensure it runs before flyway migrations in force mode
  }
}

package org.openmetadata.service.migration.mysql.v1129;

import static org.openmetadata.service.jdbi3.locator.ConnectionType.MYSQL;
import static org.openmetadata.service.migration.utils.v1129.MigrationUtil.addTriggerOperationToDefaultBotPolicies;
import static org.openmetadata.service.migration.utils.v1129.MigrationUtil.addTriggerRuleToDataStewardPolicy;

import lombok.extern.slf4j.Slf4j;
import org.openmetadata.service.migration.api.MigrationProcessImpl;
import org.openmetadata.service.migration.utils.MigrationFile;
import org.openmetadata.service.migration.utils.v1129.MigrationUtil;

@Slf4j
public class Migration extends MigrationProcessImpl {

  public Migration(MigrationFile migrationFile) {
    super(migrationFile);
  }

  @Override
  public void runDataMigration() {
    try {
      addTriggerOperationToDefaultBotPolicies(collectionDAO);
      addTriggerRuleToDataStewardPolicy(collectionDAO);
    } catch (Exception ex) {
      LOG.error(
          "Failed to migrate bot/steward trigger policies in v1129 migration. "
              + "Affected identities may lose trigger access until manually updated.",
          ex);
    }
    try {
      MigrationUtil migrationUtil = new MigrationUtil(handle, MYSQL);
      migrationUtil.migrateTaskDomains();
    } catch (Exception e) {
      LOG.error(
          "Failed to migrate task domains in v1129 migration. "
              + "Domain-scoped users may not see tasks in the activity feed "
              + "until a manual domain backfill is performed.",
          e);
    }
  }
}

