package org.openmetadata.service.monitoring;

import jakarta.annotation.Priority;
import jakarta.ws.rs.container.ContainerRequestContext;
import jakarta.ws.rs.container.ContainerRequestFilter;
import jakarta.ws.rs.container.ContainerResponseContext;
import jakarta.ws.rs.container.ContainerResponseFilter;
import jakarta.ws.rs.ext.Provider;
import lombok.extern.slf4j.Slf4j;

@Provider
@Priority(1)
@Slf4j
public class RequestMetricsFilter implements ContainerRequestFilter, ContainerResponseFilter {

  private static final String ACTIVE_REQUEST_TRACKED =
      RequestMetricsFilter.class.getName() + ".activeRequestTracked";

  private final JettyMetrics jettyMetrics;

  public RequestMetricsFilter(JettyMetrics jettyMetrics) {
    this.jettyMetrics = jettyMetrics;
  }

  @Override
  public void filter(ContainerRequestContext requestContext) {
    if (jettyMetrics == null) {
      return;
    }

    try {
      jettyMetrics.incrementActiveRequests();
      requestContext.setProperty(ACTIVE_REQUEST_TRACKED, Boolean.TRUE);
    } catch (Exception e) {
      LOG.debug("JettyMetrics not fully initialized yet: {}", e.getMessage());
    }
  }

  @Override
  public void filter(
      ContainerRequestContext requestContext, ContainerResponseContext responseContext) {
    if (!Boolean.TRUE.equals(requestContext.getProperty(ACTIVE_REQUEST_TRACKED))) {
      return;
    }
    requestContext.removeProperty(ACTIVE_REQUEST_TRACKED);
    if (jettyMetrics == null) {
      return;
    }
    try {
      jettyMetrics.decrementActiveRequests();
    } catch (Exception e) {
      LOG.debug("JettyMetrics not fully initialized yet: {}", e.getMessage());
    }
  }
}

package org.openmetadata.service.notifications.channels;

import java.util.List;
import lombok.extern.slf4j.Slf4j;
import org.commonmark.Extension;
import org.commonmark.ext.autolink.AutolinkExtension;
import org.commonmark.ext.gfm.strikethrough.StrikethroughExtension;
import org.commonmark.ext.gfm.tables.TablesExtension;
import org.commonmark.node.Node;
import org.commonmark.parser.Parser;

@Slf4j
public final class MarkdownParser {

  private MarkdownParser() {}

  private static final Parser PARSER;
  private static final int MAX_INPUT_LENGTH = 50_000;

  static {
    List<Extension> extensions =
        List.of(
            AutolinkExtension.create(), StrikethroughExtension.create(), TablesExtension.create());
    PARSER = Parser.builder().extensions(extensions).build();
  }

  public static Node parse(String markdown) {
    if (markdown == null || markdown.isEmpty()) {
      return PARSER.parse("");
    }

    if (markdown.length() > MAX_INPUT_LENGTH) {
      LOG.warn("Markdown input too large: {} characters", markdown.length());
      throw new IllegalArgumentException(
          "Markdown content exceeds maximum length of " + MAX_INPUT_LENGTH);
    }

    return PARSER.parse(markdown);
  }
}

package org.openmetadata.service.rules;

import static org.openmetadata.common.utils.CommonUtil.nullOrEmpty;

import java.util.List;
import java.util.stream.Collectors;
import org.openmetadata.schema.type.SemanticsRule;

public class RuleValidationException extends IllegalArgumentException {

  public RuleValidationException(SemanticsRule rule, String message) {
    super(formatMessage(rule, message));
  }

  public RuleValidationException(String message) {
    super(message);
  }

  public RuleValidationException(List<SemanticsRule> rules, String message) {
    super(formatMessage(rules, message));
  }

  public RuleValidationException(SemanticsRule rule, String message, Throwable throwable) {
    super(formatMessage(rule, message), throwable);
  }

  private static String formatMessage(SemanticsRule rule, String message) {
    return String.format(
        "Rule [%s] validation failed: %s. Rule context: %s",
        rule.getName(), message, rule.getDescription());
  }

  private static String formatMessage(List<SemanticsRule> rules, String message) {
    if (nullOrEmpty(rules)) {
      return message;
    }

    String rulesDetails =
        rules.stream()
            .map(
                rule ->
                    String.format(
                        "Rule [%s] validation failed: Rule context: %s",
                        rule.getName(), rule.getDescription()))
            .collect(Collectors.joining("\n"));

    return String.format("%s\n%s", message, rulesDetails);
  }
}

